
import base64

def decrypt_advanced(obfuscated):
    separator = "~"
    parts = obfuscated.split(separator)
    
    # إعادة عكس القطع
    reversed_parts = [chunk[::-1] for chunk in parts]
    b64_data = "".join(reversed_parts)
    
    # فك base64
    try:
        return base64.b64decode(b64_data).decode("utf-8")
    except:
        return ""

